sql:
SELECT products.product_name, product_groups.group_name
FROM products
JOIN product_groups ON products.group_id = product_groups.group_id;

SELECT group_name, description, parent_group_id
FROM product_groups
WHERE group_id = 1;

SELECT p.product_name, pg.group_name
FROM products p
INNER JOIN product_groups pg ON p.group_id = pg.group_id;

SELECT *
FROM continents
ORDER BY continent_name;

SELECT product_id, product_name, price
FROM products
WHERE price > (SELECT AVG(price) FROM products);

external_knowledge:
- 'seeds' metaphorically represent products;
- 'sown into the market' implies the sales quantity;
- 'harvest' refers to the total sales quantity;
- 'treasure' symbolizes the inventory (quantity in stock);
- 'fully depleted' indicates zero stock.

